#include <stdio.h>
int main() {
    int T, N, a, b, x, y;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &a, &b);
        long long sum = 0;
        int points[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &points[i][0], &points[i][1]);
        }
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int dx = abs(points[i][0] - points[j][0]);
                int dy = abs(points[i][1] - points[j][1]);
                sum += (a * dx > b * dy) ? a * dx : b * dy;
            }
        }
        printf("%lld\n", sum);
    }
    return 0;
}

